// Decide which prospecting endpoint to hit based on the payload.
// If 'domains' present -> /prospect/companies, else -> /prospect/search.
const b = $input.first().json.body || $input.first().json;
const hasDomains = Array.isArray(b.domains) && b.domains.length > 0 && !b.industries && !b.company_names;
const path = hasDomains ? 'companies' : 'search';
return [{ json: { path, payload: b } }];
